import{_ as a,c as t,o as e,b as m}from"./app.2f23aa5c.js";const h='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 24","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 24","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-27T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/24/index.md"}',o={},u=m('<div class="stanza"><a href="#s3.24" id="s3.24" class="num">3.24</a><div class="sans"><p>\u090F\u0935\u092E\u0947\u0935 \u092A\u094D\u0930\u0938\u0935\u0947\u093D\u092A\u093F \u092A\u094D\u0930\u0935\u0943\u0924\u094D\u0924\u0947 \u092F\u0926\u093F \u0924\u0941\u0930\u094D\u092F\u0930\u0938\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u0947\u0928 \u092E\u0927\u094D\u092F\u092A\u0926\u0902 \u0938\u093F\u091E\u094D\u091A\u0924\u093F \u092A\u0941\u0928\u0930\u092A\u093F \u0924\u0926\u093E\u2014</p><blockquote><p><strong>\u092E\u093E\u0924\u094D\u0930\u093E\u0938\u094D\u0935\u092A\u094D\u0930\u0924\u094D\u092F\u092F\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0928\u0937\u094D\u091F\u0938\u094D\u092F \u092A\u0941\u0928\u0930\u0941\u0924\u094D\u0925\u093E\u0928\u092E\u094D\u0965\u0968\u096A\u0965</strong></p></blockquote><p>\u092E\u093E\u0924\u094D\u0930\u093E\u0938\u0941 \u092A\u0926\u093E\u0930\u094D\u0925\u0947\u0937\u0941 \u0938\u094D\u0935\u092A\u094D\u0930\u0924\u094D\u092F\u092F\u0938\u0928\u094D\u0927\u093E\u0928\u092E\u094D\u0964</p><blockquote><p>\u091A\u0915\u094D\u0937\u0941\u0937\u093E \u092F\u0936\u094D\u091A \u0926\u0943\u0936\u094D\u092F\u0947\u0924 \u0935\u093E\u091A\u093E \u0935\u093E \u092F\u0936\u094D\u091A \u0917\u094B\u091A\u0930\u0903\u0964<br> \u092E\u0928\u0936\u094D\u091A\u093F\u0928\u094D\u0924\u092F\u0924\u0947 \u092F\u093E\u0928\u093F \u092C\u0941\u0926\u094D\u0927\u093F\u0930\u094D\u092F\u093E\u0928\u093F \u0935\u094D\u092F\u0935\u0938\u094D\u092F\u0924\u093F\u0965<br> \u0905\u0939\u0919\u094D\u0915\u0943\u0924\u093E\u0928\u093F \u092F\u093E\u0928\u094D\u092F\u0947\u0935 \u092F\u091A\u094D\u091A \u0935\u0947\u0926\u094D\u092F\u0924\u092F\u093E \u0938\u094D\u0925\u093F\u0924\u092E\u094D\u0964<br> \u092F\u0936\u094D\u091A \u0928\u093E\u0938\u094D\u0924\u093F \u0938 \u0924\u0924\u094D\u0930\u0948\u0935 \u0924\u094D\u0935\u0928\u094D\u0935\u0947\u0937\u094D\u091F\u0935\u094D\u092F\u0903 \u092A\u094D\u0930\u092F\u0924\u094D\u0928\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u0935\u093F\u0936\u094D\u0935\u092E\u093F\u0926\u092E\u0939\u092E\u093F\u0924\u093F \u091A\u093F\u0926\u094D\u0918\u0928\u093E\u0924\u094D\u092E\u0930\u0942\u092A\u0924\u093E\u0902 \u0938\u0930\u094D\u0935\u0924\u094D\u0930\u093E\u0928\u0941\u0938\u0928\u094D\u0926\u0927\u0924\u0903 \u092A\u0942\u0930\u094D\u0935\u094B\u0915\u094D\u0924\u093E\u0935\u0930\u092A\u094D\u0930\u0938\u0935\u093E\u0928\u094D\u0928\u0937\u094D\u091F\u0938\u094D\u092F\u093E\u092A\u0939\u093E\u0930\u093F\u0924\u0924\u0941\u0930\u094D\u092F\u0948\u0915\u0918\u0928\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u092E\u092F\u0938\u094D\u0935\u092D\u093E\u0935\u0938\u094D\u092F \u092A\u0941\u0928\u0930\u0941\u0924\u094D\u0925\u093E\u0928\u092E\u0941\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u0902 \u0924\u0926\u0948\u0915\u094D\u092F\u0938\u092E\u094D\u092A\u0924\u094D\u0938\u092E\u094D\u092A\u0942\u0930\u094D\u0923\u0924\u094D\u0935\u0902 \u092F\u094B\u0917\u093F\u0928\u094B \u092D\u0935\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u092A\u094D\u0930\u0938\u0939\u094D\u092F \u091A\u091E\u094D\u091A\u0932\u0940\u0924\u094D\u092F\u0947\u0935 \u092F\u094B\u0917\u093F\u0928\u093E\u092E\u092A\u093F \u092F\u0928\u094D\u092E\u0928\u0903\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>\u092F\u0938\u094D\u092F \u091C\u094D\u091E\u0947\u092F\u092E\u092F\u094B \u092D\u093E\u0935\u0903 \u0938\u094D\u0925\u093F\u0930\u0903 \u092A\u0942\u0930\u094D\u0923\u0903 \u0938\u092E\u0928\u094D\u0924\u0924\u0903\u0964<br> \u092E\u0928\u094B \u0928 \u091A\u0932\u0924\u0947 \u0924\u0938\u094D\u092F \u0938\u0930\u094D\u0935\u093E\u0935\u0938\u094D\u0925\u093E\u0917\u0924\u0938\u094D\u092F \u0924\u0941\u0965<br> \u092F\u0924\u094D\u0930 \u092F\u0924\u094D\u0930 \u092E\u0928\u094B \u092F\u093E\u0924\u093F \u091C\u094D\u091E\u0947\u092F\u0902 \u0924\u0924\u094D\u0930\u0948\u0935 \u091A\u093F\u0928\u094D\u0924\u092F\u0947\u0924\u094D\u0964<br> \u091A\u0932\u093F\u0924\u094D\u0935\u093E \u092F\u093E\u0938\u094D\u092F\u0924\u0947 \u0915\u0941\u0924\u094D\u0930 \u0938\u0930\u094D\u0935\u0902 \u0936\u093F\u0935\u092E\u092F\u0902 \u092F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964</p><blockquote><p>\u0935\u093F\u0937\u092F\u0947\u0937\u0941 \u091A \u0938\u0930\u094D\u0935\u0947\u0937\u0941 \u0907\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0930\u094D\u0925\u0947\u0937\u0941 \u091A \u0938\u094D\u0925\u093F\u0924\u0903\u0964<br> \u092F\u0924\u094D\u0930 \u092F\u0924\u094D\u0930 \u0928\u093F\u0930\u0942\u092A\u094D\u092F\u0947\u0924 \u0928\u093E\u0936\u093F\u0935\u0902 \u0935\u093F\u0926\u094D\u092F\u0924\u0947 \u0915\u094D\u0935\u091A\u093F\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F \u091A\u0965\u0968\u096A\u0965</p></div><hr><div class="trans"><p>Evameva prasave&#39;pi prav\u1E5Btte yadi turyaras\u0101va\u1E63\u1E6Dambhena madhyapada\u1E41 si\xF1cati punarapi tad\u0101\u2014</p><blockquote><p><strong>M\u0101tr\u0101svapratyayasandh\u0101ne na\u1E63\u1E6Dasya punarutth\u0101nam||24||</strong></p></blockquote><p>M\u0101tr\u0101su pad\u0101rthe\u1E63u svapratyayasandh\u0101nam|</p><blockquote><p>Cak\u1E63u\u1E63\u0101 ya\u015Bca d\u1E5B\u015Byeta v\u0101c\u0101 v\u0101 ya\u015Bca gocara\u1E25|<br> Mana\u015Bcintayate y\u0101ni buddhiry\u0101ni vyavasyati||<br> Aha\u1E45k\u1E5Bt\u0101ni y\u0101nyeva yacca vedyatay\u0101 sthitam|<br> Ya\u015Bca n\u0101sti sa tatraiva tvanve\u1E63\u1E6Davya\u1E25 prayatnata\u1E25||</p></blockquote><p>iti \u015Br\u012Bsvacchandanir\u016Bpitan\u012Bty\u0101 vi\u015Bvamidamahamiti cidghan\u0101tmar\u016Bpat\u0101\u1E41 sarvatr\u0101nusandadhata\u1E25 p\u016Brvokt\u0101varaprasav\u0101nna\u1E63\u1E6Dasy\u0101pah\u0101ritaturyaikaghanacamatk\u0101ramayasvabh\u0101vasya punarutth\u0101namunmajjana\u1E41 tadaikyasampatsamp\u016Br\u1E47atva\u1E41 yogino bhavat\u012Btyartha\u1E25| Tadukta\u1E41 \u015Br\u012Bsvacchande</p><blockquote><p>Prasahya ca\xF1cal\u012Btyeva yogin\u0101mapi yanmana\u1E25|</p></blockquote><p>ityupakramya</p><blockquote><p>Yasya j\xF1eyamayo bh\u0101va\u1E25 sthira\u1E25 p\u016Br\u1E47a\u1E25 samantata\u1E25|<br> Mano na calate tasya sarv\u0101vasth\u0101gatasya tu||<br> Yatra yatra mano y\u0101ti j\xF1eya\u1E41 tatraiva cintayet|<br> Calitv\u0101 y\u0101syate kutra sarva\u1E41 \u015Bivamaya\u1E41 yata\u1E25||</p></blockquote><p>iti|</p><blockquote><p>Vi\u1E63aye\u1E63u ca sarve\u1E63u indriy\u0101rthe\u1E63u ca sthita\u1E25|<br> Yatra yatra nir\u016Bpyeta n\u0101\u015Biva\u1E41 vidyate kvacit||</p></blockquote><p>iti ca||24||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam eva)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 [\u043D\u0438\u0437\u0448\u0438\u0445 \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439] <em>(prasave... prav\u1E5Btte)</em>, \u0435\u0441\u043B\u0438 <em>(yadi)</em> [Yog\u012B] \u0442\u0430\u043A\u0436\u0435 <em>(punar api)</em> \u043E\u043A\u0440\u043E\u043F\u0438\u0442 <em>(si\xF1cati)</em> \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u0441\u0442\u0430\u0434\u0438\u044E <em>(madhya-padam)</em> \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435\u043C <em>(ava\u1E63\u1E6Dambhena)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u0430 <em>(rasa)</em> Turya --\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F-- <em>(turya)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>\u2014</p><blockquote><p><strong>\u041F\u0440\u0438 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0438 <em>(sandh\u0101ne)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(svapratyaya)</em> \u0441 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(m\u0101tr\u0101)</em>, [\u0442\u0430\u043A\u0436\u0435] \u0432\u043D\u043E\u0432\u044C \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(punar utth\u0101nam)</em> [\u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435] \u0438\u0441\u0447\u0435\u0437\u043B\u043E <em>(na\u1E63\u1E6Dasya)</em> [\u0438\u0437-\u0437\u0430 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u043D\u0438\u0437\u0448\u0438\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0443\u043C\u0430 --\u0441\u043C. \u0430\u0444\u043E\u0440\u0438\u0437\u043C 23--] ||24||</strong></p></blockquote><p>\u0421\u043E\u044E\u0437 <em>(sandh\u0101nam)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(svapratyaya)</em> \u0441 m\u0101tr\u0101-s <em>(m\u0101tr\u0101su)</em> [\u0438\u043B\u0438] \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(pad\u0101rthe\u1E63u)</em>|</p><blockquote><p>&quot;\u0412\u0441\u0435, \u0447\u0442\u043E <em>(ya\u1E25 ca)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F <em>(d\u1E5B\u015Byeta)</em> \u0447\u0435\u0440\u0435\u0437 \u0433\u043B\u0430\u0437 [\u0430] <em>(cak\u1E63u\u1E63\u0101)</em> \u0438\u043B\u0438 <em>(v\u0101)</em> \u0432\u0441\u0435, \u0447\u0442\u043E <em>(ya\u1E25 ca)</em> [\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C <em>(gocara\u1E25)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0440\u0435\u0447\u0438 <em>(v\u0101c\u0101)</em>; \u0432\u0441\u0435, \u0447\u0442\u043E <em>(y\u0101ni)</em> \u0443\u043C <em>(manas)</em> \u0434\u0443\u043C\u0430\u0435\u0442 <em>(cintayate)</em>, \u0432\u0441\u0435, \u0447\u0442\u043E <em>(y\u0101ni)</em> \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 <em>(buddhi\u1E25)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442 <em>(vyavasyati)</em>; \u0432\u0441\u0435, \u0447\u0442\u043E <em>(y\u0101ni eva)</em> \u043F\u0440\u0438\u0441\u0432\u043E\u0435\u043D\u043E \u044D\u0433\u043E <em>(aha\u1E45k\u1E5Bt\u0101ni)</em>, \u0432\u0441\u0435, \u0447\u0442\u043E <em>(ya\u1E25 ca)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(sthitam)</em> \u043A\u0430\u043A \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435 <em>(vedyatay\u0101)</em>; \u0438 [\u0434\u0430\u0436\u0435] <em>(ca)</em> \u0447\u0442\u043E <em>(ya\u1E25)</em> \u043D\u0435 <em>(na)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(asti)</em>, \u041E\u043D --\u0442.\u0435. Parama\u015Biva, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439, \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0439 \u0438\u0437 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(sa\u1E25)</em> \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D <em>(anve\u1E63\u1E6Davya\u1E25)</em> \u0443\u0441\u0435\u0440\u0434\u043D\u043E \u0438 \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(prayatnata\u1E25)</em> \u0432 \u0442\u0435\u0445 (\u0440\u0435\u0430\u043B\u0438\u044F\u0445) <em>(tatra)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(eva tu... iti)</em><sup>1</sup>&quot;||<br> [\u0421\u043C. XII, 163-164 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C\u0438 <em>(n\u012Bty\u0101)</em>, \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C\u0438 <em>(nir\u016Bpita)</em> \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u044B\u043C <em>(\u015Br\u012B)</em> Svacchandatantra <em>(svacchanda)</em>, \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 [Yog\u012B], \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u0435\u0437\u0434\u0435 \u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0438 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 <em>(sarvatra anusandadhata\u1E25)</em> \u0441\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(\u0101tma-r\u016Bpat\u0101m)</em> \u043A\u0430\u043A \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u0443\u044E \u043C\u0430\u0441\u0441\u0443 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em> [\u0447\u0435\u0440\u0435\u0437 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0447\u0442\u043E] &quot;\u042F <em>(aham)</em> [\u0435\u0441\u0442\u044C] \u044D\u0442\u0430 <em>(idam)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam... iti)</em>&quot;, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0432\u043E\u0437\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(punar utth\u0101nam)</em> [\u0438\u043B\u0438] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(unmajjanam)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-bh\u0101vasya)</em>, \u043F\u043E\u043B\u043D\u043E\u0439 <em>(maya)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(camatk\u0101ra)</em>, [\u0432\u0438\u0434\u0438\u043C\u043E] \u043F\u043E\u043A\u0438\u043D\u0443\u0442\u043E\u0439 <em>(apah\u0101rita)</em> Turya <em>(turya)</em> \u2014\u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u044B [\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(eka-ghana)</em>\u2014 --\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 Yog\u012B \u043D\u0435 \u0431\u044B\u043B \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u0435\u043D, Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043A\u0440\u044B\u043B\u043E \u0421\u0435\u0431\u044F \u043E\u0442 \u043D\u0435\u0433\u043E--, \u043A\u043E\u0442\u043E\u0440\u0430\u044F --\u0442.\u0435. \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430-- \u0438\u0441\u0447\u0435\u0437\u043B\u0430 <em>(na\u1E63\u1E6Dasya)</em> \u0438\u0437-\u0437\u0430 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(p\u016Brva-ukta... prasav\u0101t)</em> \u043D\u0438\u0437\u0448\u0438\u0445 [\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439] <em>(avara)</em>. [\u0412\u043A\u0440\u0430\u0442\u0446\u0435,] \u043F\u043E\u043B\u043D\u043E\u0435 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 <em>(sampad-samp\u016Br\u1E47atvam)</em> [\u0435\u0433\u043E] \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 <em>(aikya)</em> \u0441 \u0442\u0435\u043C --\u0441 Turya-- <em>(tad)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> \u0441 Yog\u012B <em>(yogina\u1E25)</em>. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em>|</p><p>\u042D\u0442\u043E [\u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0443\u0447\u0435\u043D\u0438\u0435] <em>(tad)</em> \u0431\u044B\u043B\u043E \u0434\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012Bsvacchande)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(upakramya)</em>:</p><blockquote><p>&quot;\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yad)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0443\u043C <em>(manas)</em> Yog\u012B-s <em>(yogin\u0101m)</em> \u0441\u0438\u043B\u044C\u043D\u043E <em>(prasahya)</em> \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0442\u0443\u0434\u0430 \u0438 \u0441\u044E\u0434\u0430 <em>(ca\xF1cal\u012Bti eva... iti)</em><sup>2</sup>&quot;||<br> [\u0421\u043C. \u0437\u0430\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u0443\u044E \u0447\u0430\u0441\u0442\u044C IV, 311 \u0432 Svacchandatantra]</p></blockquote><p>[\u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044F \u0441]</p><blockquote><p>&quot;\u0427\u0435\u0439 <em>(yasya)</em> \u0443\u043C --\u043A\u0430\u043A \u0441\u0438\u0434\u0435\u043D\u044C\u0435 \u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u043C\u044B\u0441\u043B\u0435\u0439-- <em>(bh\u0101va\u1E25)</em> \u043F\u043E\u043B\u043E\u043D <em>(maya\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 --\u043A\u0430\u043A \u0435\u0433\u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(j\xF1eya)</em>, \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432 <em>(sthira\u1E25)</em> [\u0438] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E <em>(samantatas)</em> \u043B\u0438\u0448\u0435\u043D \u0436\u0435\u043B\u0430\u043D\u0438\u0439 <em>(p\u016Br\u1E47a\u1E25)</em>. \u0415\u0433\u043E <em>(tasya)</em> \u0443\u043C <em>(manas)</em> \u043D\u0435 <em>(na)</em> \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F <em>(calate)</em>, --\u0442.\u0435. \u043D\u0435 \u043E\u0442\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u043E\u0442 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430--, \u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430 <em>(tu)</em> \u043E\u043D \u043F\u0430\u0434\u0430\u0435\u0442 \u0432\u043E <em>(gatasya)</em> \u0432\u0441\u0435 *(sarva)*\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(avasth\u0101)</em> --\u0442.\u0435. \u0445\u043E\u0442\u044F \u043E\u043D \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u0440\u0435\u0437 \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0435 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430--. \u041A\u0443\u0434\u0430 \u0431\u044B <em>(yatra yatra)</em> [\u0435\u0433\u043E] \u0443\u043C <em>(manas)</em> \u043D\u0438 \u0434\u0432\u0438\u0433\u0430\u043B\u0441\u044F <em>(y\u0101ti)</em>, [Yog\u012B] \u0434\u043E\u043B\u0436\u0435\u043D \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0442\u044C <em>(cintayet)</em> \u043E \u0412\u044B\u0441\u0448\u0435\u043C \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0435 <em>(j\xF1eyam)</em> \u043F\u0440\u044F\u043C\u043E \u0442\u0430\u043C <em>(tatra eva)</em>. \u041D\u043E \u0435\u0441\u043B\u0438 <em>(yatas)</em> \u0432\u0441\u0435 <em>(sarvam)</em> \u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E <em>(mayam)</em> \u015Aiva <em>(\u015Biva)</em>, \u043A\u0443\u0434\u0430 <em>(kutra)</em> \u0431\u0443\u0434\u0435\u0442 \u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F [\u0435\u0433\u043E \u0443\u043C] <em>(y\u0101syate)</em> \u043F\u043E\u0441\u043B\u0435 \u043F\u0435\u0440\u0435\u043C\u0435\u0449\u0435\u043D\u0438\u044F <em>(calitv\u0101... iti)</em>?<sup>3</sup>&quot;||<br> [\u0421\u043C. IV, 312-13 \u0432 Svacchandatantra]</p></blockquote><p>\u0438 <em>(ca)</em> [\u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0441]:</p><blockquote><p>&quot;\u0412\u043E \u0432\u0441\u0435\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445 <em>(vi\u1E63aye\u1E63u... sarve\u1E63u)</em> \u0438 <em>(ca... ca)</em> \u0432\u043E \u0432\u0441\u0435\u0445 \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u044F\u0445/\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F\u0445 <em>(sarve\u1E63u... arthe\u1E63u)</em> \u0447\u0443\u0432\u0441\u0442\u0432 <em>(indriya)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438-- \u2014; [\u043B\u0443\u0447\u0448\u0438\u0439 \u0438\u0437 Yog\u012B-s \u0442\u043E\u0442], \u043A\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u044B\u043C <em>(sthita\u1E25)</em> [\u0432 \u044D\u0442\u0438 \u0440\u0435\u0430\u043B\u0438\u0438], \u0433\u0434\u0435 \u0431\u044B <em>(yatra yatra)</em> \u043E\u043D \u043D\u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u043B <em>(nir\u016Bpyeta)</em>, \u043D\u0438\u0433\u0434\u0435 <em>(kvacid... iti)</em> \u043D\u0435 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(na... vidyate)</em> \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F \u015Aiva <em>(a\u015Bivam)</em> --\u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043C\u0435\u0441\u0442\u0430, \u0433\u0434\u0435 \u0431\u044B \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043B \u015Aiva--<sup>4</sup>&quot;||<br> [\u0421\u043C. IV, 314 \u0432 Svacchandatantra]</p></blockquote><p>||24||</p><hr><ol><li><p>\u0414\u0430\u0432\u0430\u0439\u0442\u0435 \u0441\u0435\u0439\u0447\u0430\u0441 \u0447\u0435\u0442\u043A\u043E \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u0443\u0435\u043C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043C\u043E\u043C\u0435\u043D\u0442\u044B.... \u043D\u0443, \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u044F\u0441\u043D\u043E, \u043D\u0430\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E (\u0445\u0430-\u0445\u0430!):</p><ol><li><p>&quot;v\u0101c\u0101 v\u0101 ya\u015Bca gocara\u1E25&quot; - &quot;\u0438\u043B\u0438 \u0432\u0441\u0435, \u0447\u0442\u043E [\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0440\u0435\u0447\u0438&quot;: \u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0447\u0435\u0442\u044B\u0440\u0435 \u0443\u0440\u043E\u0432\u043D\u044F \u0440\u0435\u0447\u0438, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, Par\u0101v\u0101k, Pa\u015Byant\u012B, Madhyam\u0101 \u0438 Vaikhar\u012B. \u0421 \u043E\u0434\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, Par\u0101v\u0101k (\u0431\u0443\u043A\u0432. \u0432\u044B\u0441\u0448\u0430\u044F \u0440\u0435\u0447\u044C) \u2014 \u044D\u0442\u043E \u0441\u0442\u0430\u0434\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0437\u0432\u0443\u043A (v\u0101caka) \u0438 \u043E\u0431\u044A\u0435\u043A\u0442 (v\u0101cya), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442\u0441\u044F (\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F) \u0442\u0430\u043A\u0438\u043C \u0437\u0432\u0443\u043A\u043E\u043C, \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u043C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435. \u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, Vaikhar\u012B \u2014 \u044D\u0442\u043E \u0441\u0442\u0430\u0434\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 v\u0101caka \u0438 v\u0101cya \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u044B. Vaikhar\u012B \u0435\u0441\u0442\u044C \u0433\u0440\u0443\u0431\u044B\u0439 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0440\u0435\u0447\u0438, \u0442.\u0435. \u0442\u043E\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u044B\u0440\u0430\u0436\u0430\u0435\u0442\u0441\u044F \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u044F\u0437\u044B\u043A\u043E\u043C. \u0412 Vaikhar\u012B \u0438 \u0437\u0432\u0443\u043A, \u0438 \u043E\u0431\u044A\u0435\u043A\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B \u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u044B. \u041F\u043E\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0434\u0432\u0430 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u044B\u0445 \u0443\u0440\u043E\u0432\u043D\u044F, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0445 Pa\u015Byant\u012B \u0438 Madhyam\u0101. \u0412 \u043F\u0435\u0440\u0432\u043E\u043C, \u0437\u0432\u0443\u043A \u0438 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u044B\u0439 \u0438\u043C \u043E\u0431\u044A\u0435\u043A\u0442 \u043E\u0442\u043B\u0438\u0447\u043D\u044B \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430, \u043D\u043E \u043D\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u044B; \u0438 \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u043C, \u0437\u0432\u0443\u043A \u0438 \u043E\u0431\u044A\u0435\u043A\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B \u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u044B, \u043D\u043E \u043E\u043D\u0438 \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u044B &quot;\u0442\u043E\u043B\u044C\u043A\u043E&quot; \u043D\u0430 \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u043C \u0443\u0440\u043E\u0432\u043D\u0435. \u0421\u043B\u043E\u0432\u043E &quot;gocara&quot;, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442, \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0439 \u0432 \u0441\u0442\u0440\u043E\u0444\u0435 Svacchandatantra \u2014 \u044D\u0442\u043E v\u0101cya. \u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u0441\u043B\u043E\u0432\u043E &quot;v\u0101c\u0101&quot;, \u0438\u043B\u0438 &quot;\u0447\u0435\u0440\u0435\u0437 \u0440\u0435\u0447\u044C&quot; \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442\u0441\u044F &quot;\u0447\u0435\u0440\u0435\u0437 Pa\u015Byant\u012B, Madhyam\u0101 \u0438 Vaikhar\u012B&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 Par\u0101v\u0101k \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u043E\u0431\u044A\u0435\u043A\u0442\u044B. \u0422\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E! \u041E, \u0434\u0430! \u0425\u0430-\u0445\u0430! \u042D\u0442\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u0435\u0441\u0435\u043B\u043E. \u0422\u0430\u043A \u043C\u043D\u043E\u0433\u043E \u0441\u043A\u0440\u044B\u0442\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 \u0432 \u0442\u0430\u043A\u043E\u0439 \u043A\u043E\u0440\u043E\u0442\u043A\u043E\u0439 \u0444\u0440\u0430\u0437\u0435!</p></li><li><p>&quot;Mana\u015Bcintayate y\u0101ni&quot; - &quot;\u0432\u0441\u0435, \u0447\u0442\u043E \u0443\u043C \u0434\u0443\u043C\u0430\u0435\u0442&quot;: \u042D\u0442\u043E &quot;y\u0101ni&quot;, \u0438\u043B\u0438 &quot;\u0432\u0441\u0435, \u0447\u0442\u043E/\u0447\u0442\u043E \u0431\u044B \u043D\u0438&quot; \u0441\u0442\u043E\u0438\u0442 \u0432\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0447\u0438\u0441\u043B\u0435 (\u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0440\u043E\u0434\u0430). \u042D\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A sukha (\u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435), \u0438 \u0442.\u0434.</p></li><li><p>&quot;Aha\u1E45k\u1E5Bt\u0101ni y\u0101nyeva&quot; - &quot;\u0432\u0441\u0435, \u0447\u0442\u043E \u043F\u0440\u0438\u0441\u0432\u043E\u0435\u043D\u043E \u044D\u0433\u043E&quot;: \u0417\u0434\u0435\u0441\u044C \u043E\u043F\u044F\u0442\u044C &quot;y\u0101ni&quot; \u2014 \u0432\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0447\u0438\u0441\u043B\u0435 (\u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0440\u043E\u0434\u0430). \u042D\u0433\u043E \u2014 \u044D\u0442\u043E \u0442\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F 15 \u0432 \u0441\u0438\u0441\u0442\u0435\u043C\u0435 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0422\u0440\u0438\u043A\u0435. \u042D\u0433\u043E \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u0440\u0438\u0441\u0432\u0430\u0438\u0432\u0430\u0435\u0442 \u0432\u0435\u0449\u0438, \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u0430/\u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430/\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0438, \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F \u0438 \u0442.\u0434. \u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440: &quot;\u042D\u0442\u043E \u043C\u043E\u0435&quot; (\u044D\u0433\u043E \u043E\u0432\u043B\u0430\u0434\u0435\u0432\u0430\u0435\u0442 \u0432\u0435\u0449\u044C\u044E) \u0438\u043B\u0438 &quot;\u042F \u0442\u0430\u043A\u043E\u0439 \u0443\u043C\u043D\u044B\u0439&quot; (\u0437\u0434\u0435\u0441\u044C \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0437\u0430\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u0435 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E\u043C), \u0438\u043B\u0438 &quot;\u041C\u043D\u0435 \u0433\u0440\u0443\u0441\u0442\u043D\u043E&quot; (\u0441\u0435\u0439\u0447\u0430\u0441 \u043E\u043D \u043F\u0440\u0438\u0441\u0432\u0430\u0438\u0432\u0430\u0435\u0442 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0438 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F, \u0442.\u0435. \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0433\u0440\u0443\u0441\u0442\u043D\u044B\u043C), \u0438 \u0442.\u0434. \u0415\u0441\u043B\u0438 \u0432\u0430\u043C \u043D\u0443\u0436\u043D\u043E \u0431\u043E\u043B\u044C\u0448\u0435 \u043F\u0440\u0438\u043C\u0435\u0440\u043E\u0432, \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u0440\u043E\u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0439\u0442\u0435, \u0447\u0442\u043E \u0432\u0430\u0448\u0435 \u044D\u0433\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u0432\u043D\u0443\u0442\u0440\u0438 \u0432\u0430\u0441 \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441. \u041D\u043E \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u0443\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432 \u043F\u0440\u0438\u0441\u0432\u043E\u0435\u043D\u0438\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432 \u043D\u0430\u0448\u0438\u043C \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u043C \u043D\u0435\u0443\u0442\u043E\u043C\u0438\u043C\u044B\u043C \u044D\u0433\u043E, &quot;\u042F&quot; \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0432 \u043E\u0434\u0438\u043D\u043E\u0447\u0435\u0441\u0442\u0432\u0435 \u0438 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0438\u043A\u0430\u043A\u0438\u043C\u0438 \u0432\u0435\u0449\u0430\u043C\u0438, \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438, \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u043F\u0440.</p></li><li><p>&quot;yacca vedyatay\u0101 sthitam&quot; - &quot;\u0432\u0441\u0435, \u0447\u0442\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043A\u0430\u043A \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435&quot;: \u041F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435 \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0431\u044A\u0435\u043A\u0442. \u041E\u043D \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &quot;\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435&quot;, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0437\u043D\u0430\u043D \u0421\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C (\u0412\u044B\u0441\u0448\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C). \u0412\u0441\u0435, \u0447\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0437\u043D\u0430\u043D\u043E \u0421\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C, \u0435\u0441\u0442\u044C \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435. \u041F\u0440\u0430\u0432\u0434\u0430 \u043F\u0440\u043E\u0441\u0442\u043E?</p></li><li><p>&quot;Ya\u015Bca n\u0101sti&quot; - &quot;\u0438 [\u0434\u0430\u0436\u0435] \u0447\u0442\u043E \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442&quot;: \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, &quot;\u0438 \u0434\u0430\u0436\u0435 \u0447\u0442\u043E \u043D\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C&quot;.</p></li><li><p>&quot;sa...&quot; - &quot;\u041E\u043D --\u0442.\u0435. Parama\u015Biva, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439, \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0439 \u0438\u0437 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F--...&quot;: \u042D\u0442\u043E \u043D\u0435 \u043C\u043E\u0435 \u0438\u0437\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435, \u0430 \u0442\u043E, \u0447\u0442\u043E \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 \u0441\u0432\u043E\u0435\u0439 Svacchandoddyota: &quot;\u0938 \u0907\u0924\u093F \u091A\u093F\u0924\u094D\u092A\u094D\u0930\u0915\u093E\u0936\u0918\u0928\u0903 \u092A\u0930\u092E\u0936\u093F\u0935\u094B...&quot; - &quot;Sa iti citprak\u0101\u015Baghana\u1E25 parama\u015Bivo...&quot; - &quot;[\u0422\u0435\u0440\u043C\u0438\u043D] &#39;\u041E\u043D&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] Parama\u015Biva, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439, \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0439 \u0438\u0437 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F&quot;. \u041E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \u0434\u043B\u044F &quot;\u041E\u043D&quot; \u2014 &quot;sa\u1E25&quot;, \u043D\u043E &quot;\u1E25&quot; (Visarga) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0431\u0440\u043E\u0441\u0438\u0442\u044C \u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E\u0439 (&quot;t&quot; \u0432 &quot;tatraiva&quot; \u0432 \u0441\u0442\u0440\u043E\u0444\u0435 \u0432\u044B\u0448\u0435) \u0438\u0437-\u0437\u0430 10<sup>\u043E\u0433\u043E</sup> \u041F\u0440\u0430\u0432\u0438\u043B\u0430 Visarga \u0421\u0430\u043D\u0434\u0445\u0438.</p></li></ol><p>\u0412 \u0434\u0432\u0443\u0445 \u0441\u043B\u043E\u0432\u0430\u0445, \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u043E \u0443\u0441\u0435\u0440\u0434\u043D\u043E \u0438 \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u043E \u0432\u0441\u0435\u0445 \u0432\u044B\u0448\u0435\u043F\u0435\u0440\u0435\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0445 \u0440\u0435\u0430\u043B\u0438\u044F\u0445.</p></li><li><p>\u0412\u043D\u0430\u0447\u0430\u043B\u0435, \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0435, \u043F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u043E\u0435 \u0434\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432: \u041F\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043C \u0437\u0430\u043F\u043E\u043B\u043D\u044F\u0442\u044C \u043C\u043E\u0439 \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u0439 \u044F\u0449\u0438\u043A, \u0445\u0435-\u0445\u0435, \u0432\u043E\u043F\u0440\u043E\u0441\u0430\u043C\u0438 \u0438/\u0438\u043B\u0438 \u0436\u0430\u043B\u043E\u0431\u0430\u043C\u0438 \u043E\u0431 \u044D\u0442\u043E\u043C \u0441\u0442\u0440\u0430\u043D\u043D\u043E\u043C \u0441\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0438 &quot;ca\xF1cal\u012Bti&quot;, \u043F\u043E\u0437\u0432\u043E\u043B\u044C\u0442\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0448\u0430\u0433 \u0437\u0430 \u0448\u0430\u0433\u043E\u043C: &quot;ca\xF1cal\u012Bti&quot;\u2014 \u044D\u0442\u043E \u0424\u0440\u0435\u043A\u0432\u0435\u043D\u0442\u0430\u0442\u0438\u0432 (\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0439 \u0418\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u043E\u0439) \u043A\u043E\u0440\u043D\u044F &quot;cal&quot; (\u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F), \u0441\u043F\u0440\u044F\u0433\u0430\u0435\u043C\u044B\u0439 \u0432 3<sup>\u0435\u043C</sup> \u043B\u0438\u0446\u0435 \u0435\u0434\u0438\u043D\u0442\u0441\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430, \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438. \u041A\u0430\u043A \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0424\u0440\u0435\u043A\u0432\u0435\u043D\u0442\u0430\u0442\u0438\u0432 \u0443\u0441\u0438\u043B\u0438\u0432\u0430\u0435\u0442 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0433\u043B\u0430\u0433\u043E\u043B\u0430, \u0442.\u0435. &quot;calati&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043E\u043D/\u043E\u043D\u0430/\u043E\u043D\u043E \u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0441\u044F&quot; \u043D\u043E &quot;ca\xF1cal\u012Bti&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043E\u043D/\u043E\u043D\u0430/\u043E\u043D\u043E \u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E, \u0442\u0443\u0434\u0430 \u0441\u044E\u0434\u0430, \u0432\u0437\u0430\u0434 \u0432\u043F\u0435\u0440\u0435\u0434 \u0438 \u0442.\u0434.&quot;. \u0412\u044B \u043C\u043E\u0433\u043B\u0438 \u0431\u044B \u0441\u043A\u0430\u0437\u0430\u0442\u044C, &quot;\u041D\u0435\u0442, \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C ca\xF1calyate \u0442\u0430\u043A&quot;, \u043D\u043E \u0442\u0435\u043C\u0430 \u043D\u0435 \u0442\u0430\u043A \u0443\u0436 \u043F\u0440\u043E\u0441\u0442\u0430. \u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0434\u0432\u0430 \u0442\u0438\u043F\u0430 \u0424\u0440\u0435\u043A\u0432\u0435\u043D\u0442\u0430\u0442\u0438\u0432\u0430, \u043F\u0435\u0440\u0432\u044B\u0439 \u2014 \u0100tmanepad\u012B \u0438 \u0432\u0442\u043E\u0440\u043E\u0439 \u2014 Parasmaipad\u012B. \u0424\u043E\u0440\u043C\u0430 &quot;ca\xF1calyate&quot;\u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u0100tmanepad\u012B, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A &quot;ca\xF1cal\u012Bti&quot; \u2014 \u043A Parasmaipad\u012B. \u041F\u0435\u0440\u0432\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u044B\u0447\u043D\u044B\u043C \u0434\u043B\u044F \u043A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430, \u0430 \u0432\u0442\u043E\u0440\u043E\u0439 &quot;\u043E\u0431\u044B\u0447\u043D\u043E&quot; \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0412\u0435\u0434\u0430\u0445. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0432\u044B \u0441\u043A\u043E\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043E \u043D\u0435 \u043D\u0430\u0439\u0434\u0435\u0442\u0435 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439 \u043E Parasmaipad\u012B \u0424\u0440\u0435\u043A\u0432\u0435\u043D\u0442\u0430\u0442\u0438\u0432\u0435 \u0432 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u0440\u043D\u043E\u0439 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u043A\u0435. \u0414\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0432\u0430\u043C \u043D\u0443\u0436\u0435\u043D \u043A\u0442\u043E-\u0442\u043E \u0441\u0432\u0435\u0434\u0443\u0449\u0438\u0439. \u041D\u043E \u0443\u0447\u0442\u0438\u0442\u0435 \u0442\u0430\u043A\u0436\u0435, \u0447\u0442\u043E \u043A\u043E\u0440\u0435\u043D\u044C &quot;cal&quot; (\u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F) \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442 \u0441\u0432\u043E\u0439 Parasmaipad\u012B \u0424\u0440\u0435\u043A\u0432\u0435\u043D\u0442\u0430\u0442\u0438\u0432 \u043D\u0435\u0440\u0435\u0433\u0443\u043B\u044F\u0440\u043D\u043E. \u0410 \u0435\u0441\u043B\u0438 \u0443 \u043A\u043E\u0433\u043E-\u0442\u043E \u0435\u0441\u0442\u044C \u0431\u043B\u0435\u0441\u0442\u044F\u0449\u0430\u044F \u0438\u0434\u0435\u044F, \u0447\u0442\u043E &quot;ca\xF1cal\u012Bti&quot; \u0435\u0441\u0442\u044C &quot;ca\xF1cal\u012B iti&quot;, \u0442\u043E \u044D\u0442\u043E \u043D\u0438\u043A\u0430\u043A \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E. \u041F\u043E\u0447\u0435\u043C\u0443? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u0432\u044B \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0435, \u0447\u0442\u043E&quot;ca\xF1cal\u012B&quot; \u0436\u0435\u043D\u0441\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430 \u043E\u0442 &quot;ca\xF1cala&quot; (\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0442\u0443\u0434\u0430 \u0441\u044E\u0434\u0430), \u0445\u043E\u0442\u044F &quot;ca\xF1cal\u0101&quot; \u0431\u044B\u043B\u043E \u0431\u044B \u0431\u043E\u043B\u0435\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u043C, &quot;manas&quot; (\u0443\u043C) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0440\u043E\u0434\u0430. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u044F \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043D\u0430\u0440\u0443\u0448\u0430\u0435\u0442\u0441\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0432\u0435\u0440\u0438\u0442\u0435 \u0432\u044B \u043C\u043D\u0435 \u0438\u043B\u0438 \u043D\u0435\u0442, \u0437\u0434\u0435\u0441\u044C \u0432\u044B \u0438\u043C\u0435\u0435\u0442\u0435 \u044D\u0442\u043E\u0442 Parasmaipad\u012B \u0424\u0440\u0435\u043A\u0432\u0435\u043D\u0442\u0430\u0442\u0438\u0432, \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0449\u0438\u0439\u0441\u044F \u0432 \u0422\u0430\u043D\u0442\u0440\u0435, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u043E\u0433\u0434\u0430 \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u043E\u043D\u0438 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0442\u0441\u044F \u0432 \u0412\u0435\u0434\u0430\u0445. OK, \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E. \u0421 \u044D\u0442\u0438\u043C \u043A\u0440\u0430\u0442\u043A\u0438\u043C \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435\u043C, \u044F \u043F\u0440\u0435\u0434\u043E\u0442\u0432\u0440\u0430\u0442\u0438\u043B \u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u043C\u043E\u0435\u0433\u043E \u043F\u043E\u0447\u0442\u043E\u0432\u043E\u0433\u043E \u044F\u0449\u0438\u043A\u0430, \u043E\u0442\u043B\u0438\u0447\u043D\u043E!</p><p>\u0422\u0435\u043F\u0435\u0440\u044C, \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043B\u044E\u0434\u0435\u0439, \u0447\u0438\u0442\u0430\u044E\u0449\u0438\u0445 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442, K\u1E63emar\u0101ja \u0443\u0442\u043E\u0447\u043D\u044F\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u0439 Svacchandoddyota: &quot;\u0915\u0941\u091F\u093F\u0932\u0902 \u091A\u0932\u0924\u093F \u092D\u094B\u0917\u093E\u092D\u093F\u0932\u093E\u0937\u0947\u0923 \u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u092E\u0947\u0935 \u0927\u093E\u0935\u0924\u093F \u0928\u093E\u092D\u093F\u0937\u094D\u091F\u0902 \u092A\u0926\u092E\u0935\u0937\u094D\u091F\u092D\u094D\u0928\u093E\u0924\u093F \u092F\u0926\u093F\u0924\u093F \u092F\u0938\u094D\u092E\u093E\u0926\u0947\u0935\u092E\u094D\u0965\u0969\u0967\u0967\u0965&quot; - &quot;Ku\u1E6Dila\u1E41 calati bhog\u0101bhil\u0101\u1E63e\u1E47a vyutth\u0101nameva dh\u0101vati n\u0101bhi\u1E63\u1E6Da\u1E41 padamava\u1E63\u1E6Dabhn\u0101ti yaditi yasm\u0101devam||311||&quot; - &quot;[\u0422\u0435\u0440\u043C\u0438\u043D] &#39;yad&#39; [\u0432 \u0441\u0442\u0440\u043E\u0444\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u0442\u0430\u043A \u043A\u0430\u043A [\u0434\u0430\u0436\u0435 \u0443\u043C Yog\u012B-s] \u0442\u0430\u043A\u043E\u0432&#39;. [\u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u0430\u043A\u043E\u0439 \u0443\u043C] \u043D\u0435 \u0437\u0430\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 --\u0442.\u0435. Nirvyutth\u0101nasam\u0101dhi, \u0438\u043B\u0438 Sam\u0101dhi, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0435 \u043B\u044E\u0431\u043E\u0433\u043E \u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F--, \u043E\u043D \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0438 \u0431\u0435\u0436\u0438\u0442 \u0437\u0430 \u0438\u0437\u0432\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0439 vyutth\u0101na --\u043E\u0431\u044B\u0447\u043D\u044B\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- \u0438\u0437-\u0437\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u044F \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0442\u044C\u0441\u044F&quot;.</p><p>\u042F \u0434\u043E\u0431\u0430\u0432\u0438\u043B \u0441\u043B\u043E\u0432\u043E Nirvyutth\u0101nasam\u0101dhi, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043C\u0443\u0434\u0440\u0435\u0446 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u044D\u0442\u043E \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u043D\u0430 \u043F\u0435\u0440\u0432\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u044B, (\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0435 \u0431\u044B\u043B\u0430 \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0430 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u041F\u0438\u0441\u0430\u043D\u0438\u0438). \u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, Sam\u0101dhi \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 Yog\u012B, \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044F \u0432\u0441\u0435. \u0421\u0443\u043C\u043C\u0438\u0440\u0443\u044F, Sam\u0101dhi \u2014 \u044D\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441\u043E \u0432\u0441\u0435\u043C\u0438 \u0432\u0435\u0449\u0430\u043C\u0438. \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E!</p></li><li><p>\u041A\u0430\u043A \u043E\u0431\u044B\u0447\u043D\u043E \u0441\u043E Svacchandatantra, \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043B\u043E\u0436\u043D\u044B\u043C. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043C\u043D\u0435 \u043D\u0430\u0434\u043E \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441\u043D\u043E\u0432\u0430 Svacchandoddyota, \u0447\u0442\u043E\u0431\u044B \u0432\u044B \u0432\u0441\u0435 \u043F\u043E\u043D\u044F\u043B\u0438 \u043A\u0430\u043A \u0441\u043B\u0435\u0434\u0443\u0435\u0442. \u0412\u043D\u0430\u0447\u0430\u043B\u0435 \u043F\u0435\u0440\u0432\u044B\u0435 \u0434\u0432\u0435 \u0441\u0442\u0440\u043E\u043A\u0438 \u0438\u0437 \u0441\u0442\u0440\u043E\u0444\u044B IV, 312. K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435 \u0432 \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u043E\u0439 Svacchandoddyota: &quot;\u091C\u094D\u091E\u0947\u092F\u0902 \u091A \u092F\u0925\u093E \u0935\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0924\u0902 \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u092D\u093E\u0935 \u0906\u0936\u092F\u0903 \u0938\u094D\u0925\u093F\u0930\u094B \u0928\u093F\u0936\u094D\u091A\u0932\u0903 \u092A\u0942\u0930\u094D\u0923\u094B \u0928\u093F\u0930\u093E\u0915\u093E\u0919\u094D\u0915\u094D\u0937\u0903 \u0938\u092E\u0928\u094D\u0924\u0924\u0903 \u0938\u0930\u094D\u0935\u0902\u0938\u0930\u094D\u0935\u093F\u0915\u092F\u093E \u0924\u0941\u0930\u092A\u094D\u092F\u0930\u094D\u0925\u0947\u0965\u0969\u0967\u0968\u0965 &quot; - &quot;J\xF1eya\u1E41 ca yath\u0101 vy\u0101khy\u0101ta\u1E41 paratattva\u1E41 bh\u0101va \u0101\u015Baya\u1E25 sthiro ni\u015Bcala\u1E25 p\u016Br\u1E47o nir\u0101k\u0101\u1E45k\u1E63a\u1E25 samantata\u1E25 sarva\u1E41sarvikay\u0101 turapyarthe||312||&quot; - &quot;\u041A\u0430\u043A \u0431\u044B\u043B\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u043E, &#39;j\xF1eya&#39; --\u0442.\u0435. \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435--\u0435\u0441\u0442\u044C \u0412\u044B\u0441\u0448\u0438\u0439 \u041F\u0440\u0438\u043D\u0446\u0438\u043F --\u0442.\u0435. \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u043A\u0430\u043A \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043E\u0431\u044A\u0435\u043A\u0442 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u0434\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B--. [\u0422\u0435\u0440\u043C\u0438\u043D] &#39;bh\u0101va&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0443\u043C \u043A\u0430\u043A \u043C\u0435\u0441\u0442\u043E \u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u043C\u044B\u0441\u043B\u0435\u0439. &#39;Sthira&#39; [\u2014 \u044D\u0442\u043E] \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u0439, \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u0439. [\u0417\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u0441\u043B\u043E\u0432\u0430] &#39;p\u016Br\u1E47a&#39; [\u2014] \u0431\u0435\u0437 \u0436\u0435\u043B\u0430\u043D\u0438\u0439, \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439. &#39;Samantatas&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E, \u0432\u0441\u0435\u0446\u0435\u043B\u043E&#39;. [\u0418] &#39;tu&#39; [\u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0438\u0441\u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D] \u0432 \u0441\u043C\u044B\u0441\u043B\u0435 &#39;\u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430&#39;&quot;.</p><p>\u0422\u0440\u0435\u0442\u044C\u044F \u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F \u0441\u0442\u0440\u043E\u043A\u0438 \u043E\u0442\u043D\u043E\u0441\u044F\u0442\u0441\u044F \u043A \u0441\u0442\u0440\u043E\u0444\u0435 IV, 313. \u041C\u0443\u0434\u0440\u0435\u0446 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435: &quot;\u092E\u0928 \u090F\u0935 \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u0948\u0915\u094D\u092F\u092D\u093E\u0935\u0928\u093E\u0935\u093E\u0938\u093F\u0924\u0902 \u0915\u0930\u094D\u0924\u0943 \u092F\u0925\u094B\u0915\u094D\u0924\u0902 \u091C\u094D\u091E\u0947\u092F\u0902 \u0938\u0930\u094D\u0935\u0924\u094D\u0930 \u091A\u093F\u0928\u094D\u0924\u092F\u0924\u094D\u092F\u0947\u0935\u0964&quot; - &quot;Mana eva paratattvaikyabh\u0101van\u0101v\u0101sita\u1E41 kart\u1E5B yathokta\u1E41 j\xF1eya\u1E41 sarvatra cintayatyeva|&quot; - &quot;Manas --\u0443\u043C--, \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u044C, \u043D\u0430\u0445\u043E\u0434\u044F\u0441\u044C \u043F\u043E\u0434 \u0432\u043B\u0438\u044F\u043D\u0438\u0435\u043C \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C, \u0434\u0443\u043C\u0430\u0435\u0442 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043B\u0438\u0448\u044C \u043E \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u0442\u043E\u043C j\xF1eya --\u0412\u044B\u0441\u0448\u0435\u043C \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0435 \u043A\u0430\u043A \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u0435 \u0437\u043D\u0430\u043D\u0438\u044F \u0434\u043B\u044F Yog\u012B--&quot;.</p></li><li><p>\u0422\u0435\u043F\u0435\u0440\u044C \u0432\u0435\u0441\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 K\u1E63emar\u0101ja \u043D\u0430 \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0432 \u0435\u0433\u043E Svacchandoddyota:</p><p>&quot;\u0907\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093F \u091A\u093E\u0930\u094D\u0925\u0936\u094D\u091A\u0948\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0915\u0902 \u092A\u094D\u0930\u092F\u094B\u091C\u0928\u0902 \u0935\u093F\u0937\u092F\u094B\u092A\u092D\u094B\u0917\u0938\u094D\u0924\u0947\u0937\u0941 \u0938\u094D\u0925\u093F\u0924\u094B \u092F\u094B\u0917\u093F\u0935\u0930\u094B \u092F\u094B \u0928\u093F\u0930\u0942\u092A\u094D\u092F\u0947\u0924 \u0935\u093F\u091A\u093E\u0930\u094D\u092F\u0947\u0924 \u092F\u0924\u094D\u0930 \u0915\u0941\u0924\u094D\u0930\u093E\u092A\u093F \u0928\u093E\u0938\u094D\u092F\u093E\u0936\u093F\u0935\u092E\u0938\u094D\u0924\u093F \u0938\u0930\u094D\u0935\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u092A\u094D\u0930\u0915\u093E\u0936\u092E\u093E\u0928\u0924\u092F\u093E \u092A\u094D\u0930\u0915\u093E\u0936\u0918\u0928\u0936\u093F\u0935\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u093E\u0924\u094D\u0965\u0969\u0967\u096A\u0965&quot;</p><p>&quot;Indriy\u0101\u1E47i c\u0101rtha\u015Bcaindriyaka\u1E41 prayojana\u1E41 vi\u1E63ayopabhogaste\u1E63u sthito yogivaro yo nir\u016Bpyeta vic\u0101ryeta yatra kutr\u0101pi n\u0101sy\u0101\u015Bivamasti sarvasy\u0101sya prak\u0101\u015Bam\u0101natay\u0101 prak\u0101\u015Baghana\u015Bivaik\u0101tmy\u0101t||314||&quot;</p><p>&quot;\u0427\u0443\u0432\u0441\u0442\u0432\u0430 \u0438 &#39;artha&#39; \u0438\u043B\u0438 &#39;\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435/\u0446\u0435\u043B\u044C \u0447\u0443\u0432\u0441\u0442\u0432&#39;, \u0442.\u0435. \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438\u2014; \u043B\u0443\u0447\u0448\u0438\u0439 \u0438\u0437 Yog\u012B-s, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442 \u044D\u0442\u0438\u043C\u0438 [\u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044F\u043C\u0438], \u0433\u0434\u0435 \u0431\u044B \u043E\u043D \u043D\u0435 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u043B, \u0438\u043B\u0438 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043B, \u043D\u0435\u0442 \u0434\u043B\u044F \u043D\u0435\u0433\u043E \u043D\u0438 \u0435\u0434\u0438\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u015Aiva. \u0412\u0441\u0435 \u0432 \u0435\u0433\u043E \u0441\u043B\u0443\u0447\u0430\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438\u0437-\u0437\u0430 \u0435\u0433\u043E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0441 \u015Aiva, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0441\u044F \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 \u0421\u0432\u0435\u0442\u0430||314||&quot;.</p><p>\u041D\u0430\u0434\u0435\u044E\u0441\u044C, \u044F \u0431\u044B\u043B \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0438\u0441\u043A\u0443\u0441\u0435\u043D \u0438 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u0441\u043C\u044B\u0441\u043B \u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u043E\u043D\u044F\u0442\u044C \u043C\u043E\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u0441\u0442\u0440\u043E\u0444\u044B IV, 314 \u0432 Svacchandatantra.</p></li></ol></div>',1),i=[u];function r(p,y,c,n,s,q){return e(),t("div",null,i)}var d=a(o,[["render",r]]);export{h as __pageData,d as default};
